# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

def process_financial_transactions(transactions, accounts):
    """
    Process financial transactions to update account balances.

    :param transactions: List of tuples (account_id, amount) representing transactions.
    :param accounts: Dictionary of account balances {account_id: balance}
    :return: Updated dictionary of account balances
    """
    for account_id, amount in transactions:
        if account_id in accounts:
            accounts[account_id] += amount
        else:
            raise ValueError(f"Account ID {account_id} not found.")
    return accounts

# Example usage:
transactions = [(101, 500), (102, -300), (101, 200)]
accounts = {101: 1000, 102: 500}
updated_accounts = process_financial_transactions(transactions, accounts)
